const getERCaseSummary = `-- name: GetERCaseSummary :many
SELECT
    status,
    severity,
    COUNT(*)::int AS case_count,
    COUNT(*) FILTER (WHERE legal_hold)::int AS legal_hold_count,
    COUNT(*) FILTER (WHERE due_at IS NOT NULL AND due_at < NOW() AND status NOT IN ('closed','cancelled'))::int AS overdue_count
FROM hrms.er_cases
WHERE tenant_id = $1 AND NOT inactive
GROUP BY status, severity
ORDER BY status, severity
`

type GetERCaseSummaryRow struct {
	Status         string `db:"status" json:"status"`
	Severity       string `db:"severity" json:"severity"`
	CaseCount      int32  `db:"case_count" json:"case_count"`
	LegalHoldCount int32  `db:"legal_hold_count" json:"legal_hold_count"`
	OverdueCount   int32  `db:"overdue_count" json:"overdue_count"`
}

func (q *Queries) GetERCaseSummary(ctx context.Context, tenantID uuid.UUID) ([]GetERCaseSummaryRow, error) {
	rows, err := q.db.Query(ctx, getERCaseSummary, tenantID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []GetERCaseSummaryRow
	for rows.Next() {
		var i GetERCaseSummaryRow
		if err := rows.Scan(
			&i.Status,
			&i.Severity,
			&i.CaseCount,
			&i.LegalHoldCount,
			&i.OverdueCount,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

